#include<bits/stdc++.h>
using namespace std;
int a[5050],C[5050][5050],p[5050];
const long long mod=998244353;
int main()
{
    for(int i=0;i<=5000;i++)
    {
        C[i][0]=1;
        if(i>0)
        {
            p[i]=p[i-1]*2%mod;
        }
        else
        {
            p[i]=1;
        }
        for(int j=1;j<=i;j++)
        {
            C[i][j]=(C[i-1][j]+C[i-1][j-1])%mod;
        }
    }
    int c,t;
    scanf("%d%d",&c,&t);
    while(t--)
    {
        int n,m;
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
        }
        sort(a+1,a+1+n,greater<int>());
        long long ans=0;
        for(int x=1;x<min(n,m);x++)
        {
            int v=n;
            for(int y=x+1;a[y]*2>a[x]&&y<=n;y++)
            {
                if(a[x]==a[y])
                {
                    continue;
                }
                while(a[v]<a[x]-a[y])
                {
                    v--;
                }
                if(y-2<m-1-x)
                {
                    continue;
                }
                ans=(ans+1ll*C[y-2][m-1-x]*p[n-v]%mod)%mod;
            }
        }
        printf("%lld\n",((p[n]-ans)%mod+mod)%mod);
    }
    return 0;
}
